CREATE TABLE asset_references (revision_id VARCHAR(36) NOT NULL, entry_id VARCHAR(36) NOT NULL, model_id VARCHAR(36) NOT NULL, field_id VARCHAR(36) NOT NULL, asset_id VARCHAR(36) NOT NULL, json_pointer VARBINARY(2048) NOT NULL, position TINYINT UNSIGNED NOT NULL, PRIMARY KEY (revision_id,json_pointer,position), UNIQUE KEY uq_asset_references_value (revision_id,json_pointer,asset_id), KEY idx_asset_references_asset (asset_id,revision_id), KEY idx_asset_references_source (model_id,entry_id,revision_id), CONSTRAINT fk_asset_references_revision FOREIGN KEY (revision_id,entry_id,model_id) REFERENCES content_revisions (id,entry_id,model_id), CONSTRAINT fk_asset_references_field FOREIGN KEY (field_id,model_id) REFERENCES content_fields (id,model_id), CONSTRAINT fk_asset_references_asset FOREIGN KEY (asset_id) REFERENCES assets (id), CONSTRAINT chk_asset_references_pointer CHECK (LEFT(json_pointer,1)=_binary'/'), CONSTRAINT chk_asset_references_position CHECK (position<50)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_as_cs;
